import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import scala.sys.process._

object ShellCommandService extends App {
  implicit val system: ActorSystem = ActorSystem("ShellCommandService")
  implicit val executionContext: ExecutionContext = system.dispatcher

  val route =
    pathPrefix("execute") {
      post {
        entity(as[String]) { command =>
          complete {
            val userInput = command.replaceAll("\\!\\!", "")
            val result = s"command ${userInput}" ! Process
            if (result.exitValue == 0) Success(s"Command executed successfully: $userInput")
            else Failure(new RuntimeException(s"Command failed: $userInput"))
          }
        }
      }
    }

  val bindFuture = Http().bindAndHandle(route, interface = "localhost", port = 8080)
}